import bisect


class Solution:
    def countKConstraintSubstrings(self, s, k, queries):
        n = len(s)
        farthest = [0] * n
        zeros = ones = 0
        j = 0
        for i in range(n):
            if j < i:
                j = i
                zeros = ones = 0
            while j < n:
                if s[j] == '0':
                    nz, no = zeros + 1, ones
                else:
                    nz, no = zeros, ones + 1
                if min(nz, no) <= k:
                    zeros, ones = nz, no
                    j += 1
                else:
                    break
            farthest[i] = j - 1
            if s[i] == '0':
                zeros -= 1
            else:
                ones -= 1
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + (farthest[i] - i + 1)
        res = []
        for l, r in queries:
            idx = bisect.bisect_right(farthest, r, l, r + 1)
            total = prefix[idx] - prefix[l]
            t = r - idx + 1
            if t > 0:
                total += t * (t + 1) // 2
            res.append(total)
        return res

