var countKConstraintSubstrings = function(s, k, queries) {
    const n = s.length;
    const farthest = new Array(n).fill(0);
    let zeros = 0, ones = 0;
    let j = 0;
    for (let i = 0; i < n; i++) {
        if (j < i) {
            j = i;
            zeros = 0; ones = 0;
        }
        while (j < n) {
            const nz = zeros + (s[j] === '0' ? 1 : 0);
            const no = ones + (s[j] === '1' ? 1 : 0);
            if (Math.min(nz, no) <= k) {
                zeros = nz; ones = no;
                j++;
            } else {
                break;
            }
        }
        farthest[i] = j - 1;
        if (s[i] === '0') zeros--; else ones--;
    }
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + (farthest[i] - i + 1);
    }
    function bisectRight(l, r, x) {
        let lo = l, hi = r + 1;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (farthest[mid] <= x) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    }
    const res = [];
    for (const [l, r] of queries) {
        const idx = bisectRight(l, r, r);
        let total = prefix[idx] - prefix[l];
        const t = r - idx + 1;
        if (t > 0) total += t * (t + 1) / 2;
        res.push(total);
    }
    return res;
};
